if (msg.payload !== "ALARM") {
    node.warn("Build Alarm Event received non-ALARM status: " + msg.payload);
    return null;
}

if (msg.previous_status === "ALARM") {
    node.warn("Duplicate ALARM ignored. Machine is already in ALARM state.");
    return null;
}

msg.status = msg.payload;
msg.event_type = "MACHINE_ALARM";
msg.severity = "HIGH";
msg.message = msg.machine_id + " reported ALARM status";

return msg;
